namespace sv_e2731bdbab5942cb8ad225f19c8a5741.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(
    DateTimeOffset Timestamp,
    string Description,
    string Location);

using sv_e2731bdbab5942cb8ad225f19c8a5741.Client.Services;

namespace sv_e2731bdbab5942cb8ad225f19c8a5741.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-3), "Package picked up", "New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Departed facility", "New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Arrived at sorting center", "Chicago, IL"),
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-5), "Package picked up", "Seattle, WA"),
                new(DateTimeOffset.UtcNow.AddDays(-4), "In transit", "Portland, OR"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Out for delivery", "San Francisco, CA"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Delivered", "San Francisco, CA"),
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Dallas, TX",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddHours(-6), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

