using System.Net;
using System.Net.Http.Json;

namespace sv_e2731bdbab5942cb8ad225f19c8a5741.Client.Services;

public class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;
    private readonly ILogger<HttpShipmentService> _logger;

    public HttpShipmentService(HttpClient http, ILogger<HttpShipmentService> logger)
    {
        _http = http;
        _logger = logger;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
        return shipment ?? throw new InvalidOperationException("Received null shipment from server.");
    }
}

